gap: 0.75rem;\n    }\n\n    .upi-app-btn[_ngcontent-%COMP%] {\n      padding: 1rem;\n      background-color: var(--bg-tertiary);\n      border: 1px solid var(--border-color);\n      border-radius: 8px;\n      color: var(--text-primary);\n      cursor: pointer;\n      transition: all 0.2s ease;\n      font-weight: 500;\n    }\n\n    .upi-app-btn[_ngcontent-%COMP%]:hover {\n      background-color: var(--accent-primary);\n      border-color: var(--accent-primary);\n      color: white;\n      transform: translateY(-2px);\n    }\n\n    \n\n    .wallet-balance[_ngcontent-%COMP%] {\n      display: flex;\n      flex-direction: column;\n      gap: 1rem;\n    }\n\n    .balance-card[_ngcontent-%COMP%] {\n      display: flex;\n      flex-direction: column;\n      gap: 0.5rem;\n      padding: 1.5rem;\n      background: linear-gradient(135deg, var(--accent-primary) 0%, var(--accent-hover) 100%);\n      border-radius: 12px;\n      text-align: center;\n    }\n\n    .balance-label[_ngcontent-%COMP%] {\n      font-size: 0.9rem;\n      color: rgba(255, 255, 255, 0.9);\n    }\n\n    .balance-amount[_ngcontent-%COMP%] {\n      font-size: 2rem;\n      font-weight: 700;\n      color: white;\n    }\n\n    .balance-info[_ngcontent-%COMP%] {\n      display: flex;\n      align-items: center;\n      gap: 0.5rem;\n      padding: 0.75rem;\n      background-color: rgba(255, 152, 0, 0.1);\n      border: 1px solid var(--warning);\n      border-radius: 6px;\n      color: var(--warning);\n      font-size: 0.875rem;\n    }\n\n    \n\n    .modal-actions[_ngcontent-%COMP%] {\n      display: flex;\n      gap: 1rem;\n      padding-top: 1.5rem;\n      border-top: 1px solid var(--border-color);\n    }\n\n    .modal-actions[_ngcontent-%COMP%]   .btn[_ngcontent-%COMP%] {\n      flex: 1;\n    }\n\n    \n\n    @media (max-width: 768px) {\n      .payment-modal[_ngcontent-%COMP%] {\n        padding: 1.5rem;\n      }\n\n      .payment-tabs[_ngcontent-%COMP%] {\n        grid-template-columns: repeat(2, 1fr);\n     